tinymce.PluginManager.add("jl_highlight",function(i,e){i.addButton("jl_highlight",{icon:"wp_code",title:"插入代码块",onclick:function(){i.windowManager.open({title:"代码块设置",body:[{type:"label",text:"请输入代码语言,如PHP"},{type:"textbox",name:"language"}],onsubmit:function(e){var n=e.data.language,t=i.selection.getContent();i.windowManager.open({title:"请输入"+n+"代码",body:[{type:"textbox",name:"code_content",multiline:!0,minWidth:300,minHeight:150}],onsubmit:function(e){e=e.data.code_content,""===t&&(t=n+" Code Here."),e='<pre class="j-highlight language-'+n+' line-numbers"><code class="language-'+n+'">'+e+"</code></pre>";i.insertContent(e)}})}})}})});